export function getRandomChapterQuiz(chapterId: number): typeof chapterQuizQuestions {
  const pool = chapterQuizQuestions.filter(q => q.chapter === chapterId)
  const drawn = shuffleArray(pool).slice(0, CHAPTER_QUIZ_DRAW_COUNT)

  return drawn.map(q => {
    const order = shuffleArray(q.options.map((_, i) => i))
    return {
      ...q,
      options: order.map(i => q.options[i]),
      correct: order.indexOf(q.correct),
    }
  })
}
